# Module defining data structures for a task management system

class Task:
    title: str
    priority: int

    def __init__(self, title: str, priority: int):
        self.title = title
        self.priority = priority

    def __str__(self) -> str:
        return f"{{self.title}} (P{{self.priority}})"

class WorkTask(Task):
    assigned_to: str

    def __init__(self, title: str, priority: int, assigned_to: str):
        super().__init__(title, priority)
        self.assigned_to = assigned_to

    def __str__(self) -> str:
        base: str = super().__str__()
        return f"{{base}} -> {{self.assigned_to}}"

class PersonalTask(Task):
    due_date: str

    def __init__(self, title: str, priority: int, due_date: str):
        super().__init__(title, priority)
        self.due_date = due_date

    def __str__(self) -> str:
        base: str = super().__str__()
        return f"{{base}} by {{self.due_date}}"

class TaskManager:
    tasks: list[Task]

    def __init__(self):
        self.tasks = []

    def add_task(self, task: Task) -> None:
        self.tasks.append(task)

    def get_high_priority(self) -> list[Task]:
        return [t for t in self.tasks if t.priority <= 2]

def create_default_manager() -> TaskManager:
    manager: TaskManager = TaskManager()
    manager.add_task(WorkTask("Review code", 1, "Alice"))
    manager.add_task(PersonalTask("Buy groceries", 3, "Friday"))
    manager.add_task(WorkTask("Fix bug", 2, "Bob"))
    return manager

