# Utility module with helper functions

from data_structures import Task, WorkTask, PersonalTask

def sort_by_priority(tasks: list[Task]) -> list[Task]:
    # Simple bubble sort by priority
    result: list[Task] = tasks.copy()
    n: int = len(result)
    i: int = 0
    while i < n:
        j: int = 0
        while j < n - i - 1:
            if result[j].priority > result[j + 1].priority:
                temp: Task = result[j]
                result[j] = result[j + 1]
                result[j + 1] = temp
            j = j + 1
        i = i + 1
    return result

def count_work_tasks(tasks: list[Task]) -> int:
    count: int = 0
    for task in tasks:
        # Check if task is a WorkTask using type narrowing approach
        # Since we don't have isinstance with unions, we use string representation check
        # Actually, we can use hasattr-style check via exceptions or just structure it differently
        # For this test, we'll use a different approach - check via duck typing
        has_assignee: bool = hasattr_work_task(task)
        if has_assignee:
            count = count + 1
    return count

def hasattr_work_task(task: Task) -> bool:
    # Helper to check if task has assigned_to attribute
    # We use a try/except approach since we can't use isinstance with tuple
    try:
        wt: WorkTask = task as WorkTask
        return True
    except:
        return False

def task_summary(tasks: list[Task]) -> tuple[int, int]:
    total: int = len(tasks)
    work_count: int = count_work_tasks(tasks)
    return (total, work_count)
